parameters.jsCode:
// Extract keywords from website URL
const websiteUrl = $input.item.json.website_url;
const analysisId = $input.item.json.id;

// Simple keyword extraction from domain
// In production, you'd scrape the actual website content
const domain = websiteUrl.replace(/^https?:\/\//i, '').replace(/^www\./i, '').split('/')[0];
const domainParts = domain.split('.')[0].split('-');

// For now, we'll use domain as main keyword
// Later we can enhance this with actual web scraping
const mainKeywords = domainParts.filter(part => part.length > 3);

return [{
  json: {
    analysis_id: analysisId,
    website_url: websiteUrl,
    main_keywords: mainKeywords,
    // We'll use these for SerpAPI searches
    search_query_main: `${mainKeywords.join(' ')} tools`,
    search_query_alternative: `alternatives to ${mainKeywords.join(' ')}`,
    search_query_category: `${mainKeywords.join(' ')} companies`,
    // Pass through all original data
    user_id: $input.item.json.user_id,
    competitor_count: $input.item.json.competitor_count,
    social_handles: $input.item.json.social_handles,
    analysis_type: $input.item.json.analysis_type
  }
}];

// Get the SerpAPI results and user data
const serpResults = $input.first().json.organic_results || [];
const userWebsite = $('Provide relevant recommendations').first().json.website_url;
const competitorCount = $('Provide relevant recommendations').first().json.competitor_count;

// Extract domain from user's website
const getUserDomain = (url) => {
  return url.replace(/^https?:\/\//i, '').replace(/^www\./i, '').split('/')[0];
};

const userDomain = getUserDomain(userWebsite);

// Sites to exclude (marketplaces, news, etc.)
const excludeDomains = [
  'amazon.', 'ebay.', 'walmart.', 'alibaba.',
  'facebook.com', 'twitter.com', 'linkedin.com', 'instagram.com',
  'youtube.com', 'wikipedia.org', 'medium.com',
  'forbes.com', 'techcrunch.com', 'businessinsider.com'
];

// Filter and score competitors
const competitors = serpResults
  .filter(result => {
    const link = result.link || '';

    // Exclude user's own site
    if (link.includes(userDomain)) return false;

    // Exclude blacklisted domains
    if (excludeDomains.some(domain => link.includes(domain))) return false;

    return true;
  })
  .map(result => {
    // Score based on position (higher position = higher score)
    let score = 100 - (result.position * 3);

    // Bonus if title matches keywords well
    const title = (result.title || '').toLowerCase();
    if (title.includes('tool') || title.includes('software') || title.includes('platform')) {
      score += 10;
    }

    return {
      competitor_name: result.title,
      website_url: result.link,
      discovery_method: 'serpapi_main',
      serp_position: result.position,
      relevance_score: Math.max(0, Math.min(100, score)), // Keep between 0-100
      snippet: result.snippet
    };
  })
  .sort((a, b) => b.relevance_score - a.relevance_score)
  .slice(0, competitorCount); // Take only the number user requested

// Return for next node
return competitors.map(comp => ({ json: comp }));

// Get PageSpeed API response
const pageSpeedData = $input.first().json;

// Get analysis_id from the Edit Fields node (adjust node name if needed)
const analysisId = $('Edit Fields').first().json.analysis_id;
const websiteUrl = $('Edit Fields').first().json.website_url;

// Extract the important scores
const lighthouseResult = pageSpeedData.lighthouseResult || {};
const categories = lighthouseResult.categories || {};
const audits = lighthouseResult.audits || {};

// Performance score (0-1, convert to 0-100)
const performanceScore = categories.performance?.score || 0;
const pageSpeedScore = Math.round(performanceScore * 100);

// SEO score
const seoScore = categories.seo?.score || 0;
const seoScorePercent = Math.round(seoScore * 100);

// Check if mobile friendly
const mobileFriendly = audits['viewport']?.score === 1;

// Extract tech stack from detected technologies
const techStack = [];
if (lighthouseResult.stacks) {
  lighthouseResult.stacks.forEach(stack => {
    if (stack.name) techStack.push(stack.name);
  });
}

// Get some key metrics
const firstContentfulPaint = audits['first-contentful-paint']?.displayValue || 'N/A';
const speedIndex = audits['speed-index']?.displayValue || 'N/A';
const timeToInteractive = audits['interactive']?.displayValue || 'N/A';

// Build recommendations based on failed audits
const recommendations = [];

if (pageSpeedScore < 50) {
  recommendations.push('CRITICAL: Website is very slow. Immediate optimization needed.');
}
if (pageSpeedScore < 70) {
  recommendations.push('Optimize images - use WebP format and compression');
  recommendations.push('Enable text compression (gzip/brotli)');
  recommendations.push('Minify CSS and JavaScript files');
}
if (audits['unused-css-rules']?.score < 1) {
  recommendations.push('Remove unused CSS to reduce file size');
}
if (audits['unused-javascript']?.score < 1) {
  recommendations.push('Remove unused JavaScript code');
}
if (audits['uses-responsive-images']?.score < 1) {
  recommendations.push('Serve images in modern formats and appropriate sizes');
}
if (audits['offscreen-images']?.score < 1) {
  recommendations.push('Defer loading of offscreen images');
}
if (!mobileFriendly) {
  recommendations.push('Add viewport meta tag for mobile optimization');
}
if (seoScorePercent < 80) {
  recommendations.push('Improve SEO: add meta descriptions and proper heading structure');
}

// Content analysis
const contentAnalysis = {
  first_contentful_paint: firstContentfulPaint,
  speed_index: speedIndex,
  time_to_interactive: timeToInteractive,
  total_blocking_time: audits['total-blocking-time']?.displayValue || 'N/A',
  cumulative_layout_shift: audits['cumulative-layout-shift']?.displayValue || 'N/A',
  largest_contentful_paint: audits['largest-contentful-paint']?.displayValue || 'N/A'
};

// Return structured data ready for database - NOW WITH analysis_request_id
return [{
  json: {
    analysis_request_id: analysisId,  // ← FIXED: Now included!
    website_url: websiteUrl,
    page_speed_score: pageSpeedScore,
    mobile_friendly: mobileFriendly,
    seo_score: seoScorePercent,
    tech_stack: techStack,
    traffic_estimate: null,
    backlinks_count: null,
    content_analysis: contentAnalysis,
    recommendations: recommendations,
    raw_data: {
      performance_score: pageSpeedScore,
      seo_score: seoScorePercent,
      accessibility_score: Math.round((categories.accessibility?.score || 0) * 100),
      best_practices_score: Math.round((categories['best-practices']?.score || 0) * 100),
      note: 'Extracted from Google PageSpeed Insights API'
    }
  }
}];

// Get social handles and analysis ID
const socialHandles = $('Provide relevant recommendations').first().json.social_handles || {};
const analysisId = $('Provide relevant recommendations').first().json.analysis_id;

// Convert social handles object into array of items (one per platform)
const platforms = [];

if (socialHandles.instagram) {
  platforms.push({
    platform: 'instagram',
    handle: socialHandles.instagram,
    analysis_request_id: analysisId
  });
}

if (socialHandles.facebook) {
  platforms.push({
    platform: 'facebook',
    handle: socialHandles.facebook,
    analysis_request_id: analysisId
  });
}

if (socialHandles.tiktok) {
  platforms.push({
    platform: 'tiktok',
    handle: socialHandles.tiktok,
    analysis_request_id: analysisId
  });
}

if (socialHandles.linkedin) {
  platforms.push({
    platform: 'linkedin',
    handle: socialHandles.linkedin,
    analysis_request_id: analysisId
  });
}

if (socialHandles.twitter) {
  platforms.push({
    platform: 'twitter',
    handle: socialHandles.twitter,
    analysis_request_id: analysisId
  });
}

if (socialHandles.youtube) {
  platforms.push({
    platform: 'youtube',
    handle: socialHandles.youtube,
    analysis_request_id: analysisId
  });
}

// Return array of platforms (one item per platform)
return platforms.map(p => ({ json: p }));

// Get Apify results (10 items)
const apifyResults = $input.all();

// Get competitor data from database (from earlier in workflow)
const competitorsFromDB = $('insert competitors').all().map(item => item.json);

// Process each Apify result
const competitorsWithSocial = [];

apifyResults.forEach(item => {
  const result = item.json;
  const domain = result.domain || '';
  const startUrl = result.start_urls?.[0] || '';

  // Find matching competitor from database by comparing domains
  const matchingCompetitor = competitorsFromDB.find(comp => {
    const compDomain = (comp.website_url || comp.website || '')
      .replace(/^https?:\/\//, '')
      .replace(/^www\./, '')
      .split('/')[0];

    return domain.includes(compDomain) || compDomain.includes(domain.replace(/^www\./, ''));
  });

  if (!matchingCompetitor) {
    console.log(`⚠️ Could not match ${domain} to any competitor in database`);
    return; // Skip this one
  }

  // Extract social handles
  const socialHandles = {};

  if (result.instagram_urls && result.instagram_urls.length > 0) {
    const instaMatch = result.instagram_urls[0].match(/instagram\.com\/([a-zA-Z0-9_.]+)/);
    if (instaMatch && instaMatch[1]) {
      socialHandles.instagram = instaMatch[1].replace(/\//g, '');
    }
  }

  if (result.tiktok_urls && result.tiktok_urls.length > 0) {
    const tiktokMatch = result.tiktok_urls[0].match(/tiktok\.com\/@([a-zA-Z0-9_.]+)/);
    if (tiktokMatch && tiktokMatch[1]) {
      socialHandles.tiktok = tiktokMatch[1];
    }
  }

  if (result.facebook_urls && result.facebook_urls.length > 0) {
    const fbUrl = result.facebook_urls.find(url => 
      !url.includes('/about/') && 
      !url.includes('/sharer/') &&
      !url.includes('/login')
    );
    if (fbUrl) {
      const fbMatch = fbUrl.match(/facebook\.com\/([a-zA-Z0-9.-]+)/);
      if (fbMatch && fbMatch[1]) {
        socialHandles.facebook = fbMatch[1];
      }
    }
  }

  if (result.linkedin_urls && result.linkedin_urls.length > 0) {
    const linkedinMatch = result.linkedin_urls[0].match(/linkedin\.com\/(?:company|in)\/([a-zA-Z0-9-]+)/);
    if (linkedinMatch && linkedinMatch[1]) {
      socialHandles.linkedin = linkedinMatch[1];
    }
  }

  if (result.twitter_urls && result.twitter_urls.length > 0) {
    const twitterMatch = result.twitter_urls[0].match(/(?:twitter|x)\.com\/([a-zA-Z0-9_]+)/);
    if (twitterMatch && twitterMatch[1]) {
      socialHandles.twitter = twitterMatch[1];
    }
  }

  if (result.youtube_urls && result.youtube_urls.length > 0) {
    const youtubeMatch = result.youtube_urls[0].match(/youtube\.com\/(?:channel|c|user)\/([a-zA-Z0-9_-]+)/);
    if (youtubeMatch && youtubeMatch[1]) {
      socialHandles.youtube = youtubeMatch[1];
    }
  }

  // Only add if we found at least one social media handle
  if (Object.keys(socialHandles).length > 0) {
    competitorsWithSocial.push({
      competitor_id: matchingCompetitor.id,
      competitor_name: matchingCompetitor.competitor_name || matchingCompetitor.name,
      website_url: matchingCompetitor.website_url || matchingCompetitor.website,
      social_handles: socialHandles,
      analysis_request_id: matchingCompetitor.analysis_request_id,
      apify_stats: {
        pages_crawled: result.pages_crawled,
        is_cloudflare_protected: result.is_cloudflare_protected
      }
    });

    console.log(`✅ ${matchingCompetitor.competitor_name}: Found ${Object.keys(socialHandles).length} social platforms`);
  } else {
    console.log(`❌ ${matchingCompetitor.competitor_name}: No social media found`);
  }
});

return competitorsWithSocial.map(c => ({ json: c }));

// Get all competitors with social handles
const competitors = $input.all();

const allPlatforms = [];

// For each competitor, create one item per platform
competitors.forEach(competitor => {
  const comp = competitor.json;

  // Loop through each social platform they have
  for (const [platform, handle] of Object.entries(comp.social_handles)) {
    if (handle && handle.length > 0) {

      // Construct profile URL based on platform
      let profileUrl = '';

      switch(platform) {
        case 'instagram':
          profileUrl = `https://www.instagram.com/${handle.replace('@', '')}`;
          break;
        case 'facebook':
          profileUrl = `https://www.facebook.com/${handle}`;
          break;
        case 'tiktok':
          profileUrl = `https://www.tiktok.com/@${handle.replace('@', '')}`;
          break;
        case 'linkedin':
          // Check if it's a company or personal profile
          if (handle.includes('/') || /^\d+$/.test(handle)) {
            // Numeric ID or already formatted
            profileUrl = handle.startsWith('http') 
              ? handle 
              : `https://www.linkedin.com/company/${handle}`;
          } else {
            // Personal profile
            profileUrl = `https://www.linkedin.com/in/${handle}`;
          }
          break;
        case 'twitter':
          profileUrl = `https://twitter.com/${handle.replace('@', '')}`;
          break;
        case 'youtube':
          profileUrl = handle.startsWith('http')
            ? handle
            : `https://www.youtube.com/${handle}`;
          break;
        default:
          profileUrl = handle;
      }

      allPlatforms.push({
        competitor_id: comp.competitor_id,
        competitor_name: comp.competitor_name,
        platform: platform,
        handle: handle,
        profile_url: profileUrl,
        analysis_request_id: comp.analysis_request_id,
        is_competitor: true
      });
    }
  }
});

console.log(`Total platforms to scrape: ${allPlatforms.length}`);
allPlatforms.forEach(p => {
  console.log(`${p.platform}: ${p.profile_url}`);
});

return allPlatforms.map(p => ({ json: p }));

